VALUES ('cannon:squad', 'cannon', 'squad', 'cannon.squad.v1', 1, '2026-06-11T00:00:00.000Z', NULL, 'fnv1a:00000000', 'manual', 'launch-seed', '{"season":"2026/27","players":[{"id":"raya","num":22,"name":"Raya","full":"David Raya","nat":"ESP","pos":"GK","group":"Goalkeepers","availability":"fit","availabilityNote":null,"stats":{"apps":35,"goals":0,"assists":0,"rating":7.8},"form":["W","W","W","D","W"],"note":"Golden Glove holder. Eighteen clean sheets in the title season."},{"id":"hein","num":13,"name":"Hein","full":"Karl Hein","nat":"EST","pos":"GK","group":"Goalkeepers","availability":"fit","availabilityNote":null,"stats":{"apps":3,"goals":0,"assists":0,"rating":6.8},"form":["W","W","D","W","W"],"note":"Cup keeper. Reliable when called on."},{"id":"saliba","num":12,"name":"Saliba","full":"William Saliba","nat":"FRA","pos":"CB","group":"Defenders","availability":"fit","availabilityNote":null,"stats":{"apps":36,"goals":2,"assists":2,"rating":8.2},"form":["W","W","W","D","W"],"note":"The platform everything is built on. Barely missed a minute."},{"id":"gabriel","num":6,"name":"Gabriel","full":"Gabriel Magalhães","nat":"BRA","pos":"CB","group":"Defenders","availability":"fit","availabilityNote":null,"stats":{"apps":34,"goals":3,"assists":1,"rating":8},"form":["W","W","D","W","W"],"note":"Set-piece menace at both ends. The league''s best duelling centre-half."},{"id":"white","num":2,"name":"White","full":"Ben White","nat":"ENG","pos":"RB","group":"Defenders","availability":"doubt","availabilityNote":"Knee — managed in pre-season, expected for opening day","stats":{"apps":32,"goals":1,"assists":5,"rating":7.8},"form":["W","D","W","W","W"],"note":"Underlaps, overlaps, and the best long throw at the club."},{"id":"zinchenko","num":3,"name":"Zinchenko","full":"Oleksandr Zinchenko","nat":"UKR","pos":"LB","group":"Defenders","availability":"fit","availabilityNote":null,"stats":{"apps":28,"goals":1,"assists":4,"rating":7.4},"form":["W","W","W","D","W"],"note":"Inverts into midfield to make the build-up sing."},{"id":"tomiyasu","num":18,"name":"Tomiyasu","full":"Takehiro Tomiyasu","nat":"JPN","pos":"RB","group":"Defenders","availability":"injured","availabilityNote":"Calf — back in full training late August","stats":{"apps":20,"goals":0,"assists":1,"rating":7.2},"form":["W","W","D","W","W"],"note":"The squad''s quiet Swiss army knife — covers every defensive slot."},{"id":"rice","num":41,"name":"Rice","full":"Declan Rice","nat":"ENG","pos":"CM","group":"Midfielders","availability":"fit","availabilityNote":null,"stats":{"apps":38,"goals":9,"assists":15,"rating":8.2},"form":["W","W","D","W","W"],"note":"Played every league game of the title season. The engine and the shield."},{"id":"odegaard","num":8,"name":"Ødegaard","full":"Martin Ødegaard","nat":"NOR","pos":"AM","group":"Midfielders","availability":"fit","availabilityNote":null,"stats":{"apps":36,"goals":14,"assists":22,"rating":8.7},"form":["W","W","W","D","W"],"note":"Captain. Twenty-two assists — the most by any player in the league."},{"id":"trossard","num":19,"name":"Trossard","full":"Leandro Trossard","nat":"BEL","pos":"AM","group":"Midfielders","availability":"fit","availabilityNote":null,"stats":{"apps":28,"goals":11,"assists":8,"rating":7.6},"form":["W","D","W","W","W"],"note":"The finisher of broken games. Eleven goals, most from the bench."},{"id":"merino","num":5,"name":"Merino","full":"Mikel Merino","nat":"ESP","pos":"CM","group":"Midfielders","availability":"fit","availabilityNote":null,"stats":{"apps":25,"goals":4,"assists":6,"rating":7.5},"form":["W","W","W","D","W"],"note":"Aerial control in both boxes; the late-game closer."},{"id":"saka","num":7,"name":"Saka","full":"Bukayo Saka","nat":"ENG","pos":"RW","group":"Forwards","availability":"fit","availabilityNote":null,"stats":{"apps":37,"goals":24,"assists":18,"rating":8.4},"form":["W","W","D","W","W"],"note":"Starboy. 24 goals and 18 assists in the title year. Contract talks ongoing."},{"id":"martinelli","num":11,"name":"Martinelli","full":"Gabriel Martinelli","nat":"BRA","pos":"LW","group":"Forwards","availability":"fit","availabilityNote":null,"stats":{"apps":34,"goals":21,"assists":11,"rating":7.9},"form":["W","D","W","W","W"],"note":"Back to his terrifying best — 21 goals, most of them in transition."},{"id":"havertz","num":29,"name":"Havertz","full":"Kai Havertz","nat":"GER","pos":"CF","group":"Forwards","availability":"fit","availabilityNote":null,"stats":{"apps":35,"goals":36,"assists":13,"rating":8},"form":["W","W","W","D","W"],"note":"Thirty-six goals. The signing nobody believed in became the league''s best nine."},{"id":"jesus","num":9,"name":"Jesus","full":"Gabriel Jesus","nat":"BRA","pos":"CF","group":"Forwards","availability":"doubt","availabilityNote":"Returning from knee rehab — minutes managed through August","stats":{"apps":22,"goals":12,"assists":7,"rating":7.3},"form":["W","W","D","W","W"],"note":"The press-leader. Changes what the front line is when he plays."}]}', 1781136000000);
--> statement-breakpoint
